"use client";

// localStorage wrapper — reemplaza window.storage del artifact de Claude
const storageAPI = {
  async get(key, shared) {
    try {
      const pfx = shared ? "piola_s_" : "piola_";
      const val = localStorage.getItem(pfx + key);
      if (val === null) throw new Error("not found");
      return { key, value: val, shared: !!shared };
    } catch { return null; }
  },
  async set(key, value, shared) {
    try {
      const pfx = shared ? "piola_s_" : "piola_";
      localStorage.setItem(pfx + key, value);
      return { key, value, shared: !!shared };
    } catch { return null; }
  },
};
if (typeof window !== "undefined") {
  window.storage = window.storage || storageAPI;
}

