// Mapeo Supabase (snake_case) <-> JS (camelCase)
const dbToProduct = (row) => ({
  id: row.id,
  brand: row.brand,
  name: row.name,
  model: row.model || "",
  category: row.category || "Camperas",
  type: row.type || "stock",
  priceUSD: row.price_usd || 0,
  description: row.description || "",
  sizes: row.sizes || ["S","M","L","XL"],
  colors: row.colors || [],
  stock: row.stock || 0,
  featured: row.featured || false,
  imageKey: row.id,
  images: row.images || [],
  _previewUrls: row.images || [],
});

const productToDb = (p) => ({
  id: p.id,
  brand: p.brand,
  name: p.name,
  model: p.model || "",
  category: p.category || "Camperas",
  type: p.type || "stock",
  price_usd: p.priceUSD || 0,
  description: p.description || "",
  sizes: p.sizes || [],
  colors: (p.colors || []).filter((c) => c && c.trim()),
  stock: p.stock || 0,
  featured: p.featured || false,
  images: p._previewUrls || p.images || [],
});

