// Auto-generated product images (base64 JPEGs, ~500px, Q72)
const PRODUCT_IMAGES = {"tnf_nuptse_zebra": ["", "", ""], "tnf_nuptse_kaws": ["", "", ""], "tnf_nuptse_black": ["", "", ""], "tnf_nuptse_colors": ["", "", ""], "tnf_nuptse_olive": ["", "", ""], "tnf_vest_yellow": ["", "", ""], "tnf_mountain": ["", "", ""], "nike_hoodie_black": ["", "", ""], "nocta_tee_black": ["", "", ""], "nocta_tracksuit_purple": ["", "", ""], "nocta_tights": ["", "", ""], "sup_nike_corduroy": ["", "", ""], "nike_acg_awr": ["", "", ""], "sup_tnf_backpack": ["", "", ""], "nike_techfleece_set": ["", "", ""], "supreme_tee_black": ["", "", ""], "corteiz_alcatraz": ["", "", ""], "nike_techfleece_grey": ["", "", ""]};

const img = (key, idx = 0, product = null) => {
  // 1. _previewUrls (admin session uploads, aún no guardados)
  if (product && product._previewUrls && product._previewUrls[idx]) {
    return product._previewUrls[idx];
  }
  // 2. images[] de Supabase (dataURIs o URLs guardadas)
  if (product && product.images && product.images[idx]) {
    const v = product.images[idx];
    if (v.startsWith("data:") || v.startsWith("http")) return v;
  }
  // 3. PRODUCT_IMAGES embebidas (productos seed del zip original)
  const arr = PRODUCT_IMAGES[key];
  if (!arr || !arr[idx]) return "";
  return `data:image/jpeg;base64,${arr[idx]}`;
};

