const StoreCtx = createContext(null);
const useStore = () => useContext(StoreCtx);

// Fetcher del dólar blue con cache y fallback
function useExchangeRate() {
  const [rate, setRate] = useState({ value: 1400, loading: true, source: "fallback", updatedAt: null });

  useEffect(() => {
    let alive = true;
    async function load() {
      // cache 1h
      try {
        const cached = await window.storage.get("blue_rate_cache", true);
        if (cached && cached.value) {
          const c = JSON.parse(cached.value);
          if (Date.now() - c.ts < 60 * 60 * 1000) {
            if (alive) setRate({ value: c.value, loading: false, source: "cache", updatedAt: c.ts });
            return;
          }
        }
      } catch {}

      try {
        const r = await fetch("https://dolarapi.com/v1/dolares/blue");
        const j = await r.json();
        const venta = j.venta || 1400;
        if (!alive) return;
        setRate({ value: venta, loading: false, source: "live", updatedAt: Date.now() });
        try {
          await window.storage.set(
            "blue_rate_cache",
            JSON.stringify({ value: venta, ts: Date.now() }),
            true
          );
        } catch {}
      } catch (e) {
        if (alive) setRate({ value: 1400, loading: false, source: "fallback", updatedAt: Date.now() });
      }
    }
    load();
    return () => {
      alive = false;
    };
  }, []);

  return rate;
}

// Persistencia de productos del admin
function useProducts() {
  const [products, setProducts] = useState(SEED_PRODUCTS);
  const [loaded, setLoaded] = useState(false);

  // Cargar productos de Supabase al montar
  useEffect(() => {
    (async () => {
      try {
        const { data, error } = await supabase
          .from("products")
          .select("*")
          .order("created_at", { ascending: false });
        if (!error && data && data.length > 0) {
          setProducts(data.map(dbToProduct));
        }
        // Si no hay productos en Supabase, mantener SEED_PRODUCTS como demo
      } catch {}
      setLoaded(true);
    })();
  }, []);

  const persist = async (next) => {
    setProducts(next);
    // No guardamos en localStorage — Supabase es la fuente de verdad
  };

  // Funciones CRUD contra Supabase
  const addProduct = async (product) => {
    const dbRow = productToDb(product);
    const { error } = await supabase.from("products").insert(dbRow);
    if (error) { console.error("Error guardando producto:", error); return false; }
    setProducts((prev) => [product, ...prev]);
    return true;
  };

  const updateProduct = async (product) => {
    const dbRow = productToDb(product);
    const { error } = await supabase.from("products").update(dbRow).eq("id", product.id);
    if (error) { console.error("Error actualizando:", error); return false; }
    setProducts((prev) => prev.map((p) => p.id === product.id ? product : p));
    return true;
  };

  const deleteProduct = async (id) => {
    const { error } = await supabase.from("products").delete().eq("id", id);
    if (error) { console.error("Error eliminando:", error); return false; }
    setProducts((prev) => prev.filter((p) => p.id !== id));
    return true;
  };

  return { products, setProducts: persist, addProduct, updateProduct, deleteProduct, loaded };
}

// Formateo de precio
function usePrice(usd) {
  const { exchangeRate } = useStore();
  const ars = Math.round((usd * exchangeRate.value) / 100) * 100;
  return {
    usd: `US$${usd.toLocaleString("en-US")}`,
    ars: `$${ars.toLocaleString("es-AR")}`,
  };
}

