const FONT_STACK_DISPLAY = `'Archivo Black', 'Arial Black', sans-serif`;
const FONT_STACK_BODY = `'Hanken Grotesk', system-ui, -apple-system, sans-serif`;
const FONT_STACK_MONO = `'JetBrains Mono', ui-monospace, monospace`;

function Price({ usd, size = "md", inverted = false, dark = false }) {
  const p = usePrice(usd);
  const sizes = {
    sm: { u: "text-sm", a: "text-xs" },
    md: { u: "text-lg", a: "text-sm" },
    lg: { u: "text-3xl", a: "text-base" },
    xl: { u: "text-5xl", a: "text-lg" },
  };
  const s = sizes[size];
  // Default: texto negro sobre fondo claro. dark=true si está sobre fondo oscuro.
  const textColor = dark ? COLORS.blanco : COLORS.negro;
  const subColor = dark ? COLORS.grisText : COLORS.grisTextLight;
  return (
    <div className="flex flex-col leading-none">
      <span
        className={`${s.u} font-black tracking-tight`}
        style={{ fontFamily: FONT_STACK_DISPLAY, color: textColor }}
      >
        {p.usd}
      </span>
      <span
        className={`${s.a} mt-1`}
        style={{
          fontFamily: FONT_STACK_MONO,
          color: subColor,
          letterSpacing: "-0.02em",
        }}
      >
        ≈ {p.ars} ARS
      </span>
    </div>
  );
}

function Badge({ children, color = "celeste", size = "sm" }) {
  const map = {
    celeste: { bg: COLORS.celeste, fg: COLORS.negro },
    amarillo: { bg: COLORS.amarillo, fg: COLORS.negro },
    negro: { bg: COLORS.negro, fg: COLORS.blanco },
    blanco: { bg: COLORS.blanco, fg: COLORS.negro },
    outline: { bg: "transparent", fg: COLORS.blanco, border: COLORS.grisBorder },
    "outline-light": { bg: "transparent", fg: COLORS.negro, border: COLORS.borderLight },
    "outline-dark": { bg: "transparent", fg: COLORS.negro, border: COLORS.negro },
    red: { bg: "#DC2626", fg: COLORS.blanco },
    green: { bg: "#10B981", fg: COLORS.negro },
  };
  const c = map[color] || map.celeste;
  const sz = size === "sm" ? "px-2 py-0.5 text-[10px]" : "px-3 py-1 text-xs";
  return (
    <span
      className={`${sz} uppercase font-black tracking-wider inline-flex items-center`}
      style={{
        background: c.bg,
        color: c.fg,
        fontFamily: FONT_STACK_DISPLAY,
        border: c.border ? `1px solid ${c.border}` : "none",
        letterSpacing: "0.1em",
      }}
    >
      {children}
    </span>
  );
}

function Btn({ children, onClick, variant = "primary", size = "md", className = "", disabled, type = "button" }) {
  const variants = {
    primary: { bg: COLORS.amarillo, fg: COLORS.negro, hv: COLORS.amarilloSoft },
    celeste: { bg: COLORS.celeste, fg: COLORS.negro, hv: COLORS.celesteDeep },
    dark: { bg: COLORS.negro, fg: COLORS.blanco, hv: "#222" },
    ghost: { bg: "transparent", fg: COLORS.negro, hv: "#F0F0F0", border: COLORS.negro },
    white: { bg: COLORS.blanco, fg: COLORS.negro, hv: "#EEE" },
  };
  const v = variants[variant];
  const sizes = {
    sm: "px-4 py-2 text-xs",
    md: "px-6 py-3 text-sm",
    lg: "px-8 py-4 text-base",
  };
  return (
    <button
      type={type}
      disabled={disabled}
      onClick={onClick}
      className={`${sizes[size]} uppercase font-black tracking-widest inline-flex items-center justify-center gap-2 transition-colors disabled:opacity-40 disabled:cursor-not-allowed ${className}`}
      style={{
        background: v.bg,
        color: v.fg,
        fontFamily: FONT_STACK_DISPLAY,
        border: v.border ? `1px solid ${v.border}` : "none",
        letterSpacing: "0.1em",
      }}
      onMouseEnter={(e) => !disabled && (e.currentTarget.style.background = v.hv)}
      onMouseLeave={(e) => !disabled && (e.currentTarget.style.background = v.bg)}
    >
      {children}
    </button>
  );
}

// Mini bandera argentina animada (SVG)
function FlagAR({ size = 40, spinning = false }) {
  return (
    <div
      className="relative overflow-hidden shrink-0"
      style={{ width: size, height: size, borderRadius: "50%", border: `2px solid ${COLORS.negro}` }}
    >
      <div className="absolute inset-0" style={{ background: COLORS.celeste, height: "33%" }} />
      <div className="absolute inset-0" style={{ background: COLORS.blanco, top: "33%", height: "34%" }} />
      <div className="absolute inset-0" style={{ background: COLORS.celeste, top: "67%", height: "33%" }} />
      <div
        className={"absolute inset-0 flex items-center justify-center" + (spinning ? " piola-spin" : "")}
        style={{ transformOrigin: "center" }}
      >
        <svg viewBox="0 0 100 100" style={{ width: size * 0.5, height: size * 0.5 }}>
          <circle cx="50" cy="50" r="14" fill={COLORS.amarillo} />
          {Array.from({ length: 16 }).map((_, i) => {
            const a = (i / 16) * Math.PI * 2;
            const x1 = 50 + Math.cos(a) * 16;
            const y1 = 50 + Math.sin(a) * 16;
            const x2 = 50 + Math.cos(a) * 26;
            const y2 = 50 + Math.sin(a) * 26;
            return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={COLORS.amarillo} strokeWidth="2" />;
          })}
        </svg>
      </div>
    </div>
  );
}

// Logo de texto PIOLA.AR con el tilde celeste sobre la i
function LogoText({ size = 32, color = COLORS.blanco }) {
  return (
    <div
      className="relative inline-flex items-baseline leading-none"
      style={{ fontFamily: FONT_STACK_DISPLAY, fontSize: size, color, letterSpacing: "-0.04em" }}
    >
      <span className="font-black">P</span>
      <span className="relative font-black">
        i
        <span
          className="absolute rounded-full"
          style={{
            width: size * 0.22,
            height: size * 0.22,
            background: COLORS.celeste,
            top: -size * 0.05,
            left: "50%",
            transform: "translateX(-50%)",
          }}
        />
      </span>
      <span className="font-black">OLA</span>
      <span className="font-black" style={{ fontSize: size * 0.5, marginLeft: size * 0.04 }}>
        .AR
      </span>
    </div>
  );
}

