// Modal de zoom con pan y wheel-zoom
function ZoomModal({ src, alt, onClose, onPrev, onNext }) {
  const [scale, setScale] = useState(1);
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const [dragging, setDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  useEffect(() => {
    // Reset al cambiar imagen
    setScale(1);
    setPos({ x: 0, y: 0 });
  }, [src]);

  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "Escape") onClose();
      if (e.key === "ArrowLeft" && onPrev) onPrev();
      if (e.key === "ArrowRight" && onNext) onNext();
    };
    window.addEventListener("keydown", onKey);
    document.body.style.overflow = "hidden";
    return () => {
      window.removeEventListener("keydown", onKey);
      document.body.style.overflow = "";
    };
  }, [onClose, onPrev, onNext]);

  const onWheel = (e) => {
    e.preventDefault();
    const delta = e.deltaY < 0 ? 0.2 : -0.2;
    setScale((s) => Math.min(Math.max(1, s + delta), 5));
  };

  const onMouseDown = (e) => {
    if (scale <= 1) return;
    setDragging(true);
    setDragStart({ x: e.clientX - pos.x, y: e.clientY - pos.y });
  };

  const onMouseMove = (e) => {
    if (!dragging) return;
    setPos({ x: e.clientX - dragStart.x, y: e.clientY - dragStart.y });
  };

  const onMouseUp = () => setDragging(false);

  const toggleZoom = () => {
    if (scale > 1) {
      setScale(1);
      setPos({ x: 0, y: 0 });
    } else {
      setScale(2.5);
    }
  };

  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center"
      style={{ background: "rgba(10,10,10,0.95)", backdropFilter: "blur(8px)" }}
      onWheel={onWheel}
      onMouseMove={onMouseMove}
      onMouseUp={onMouseUp}
      onMouseLeave={onMouseUp}
    >
      {/* Controles */}
      <button
        onClick={onClose}
        className="absolute top-6 right-6 p-3 z-10 hover:bg-white/10 transition"
        style={{ color: COLORS.blanco }}
      >
        <X size={28} />
      </button>

      <div
        className="absolute top-6 left-6 z-10 flex items-center gap-2 text-xs uppercase tracking-widest"
        style={{ color: COLORS.blanco, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
      >
        <span>Zoom: {Math.round(scale * 100)}%</span>
        <button
          onClick={() => setScale((s) => Math.max(1, s - 0.5))}
          className="ml-4 w-8 h-8 flex items-center justify-center hover:bg-white/10"
          style={{ border: `1px solid ${COLORS.blanco}` }}
        >
          <Minus size={14} />
        </button>
        <button
          onClick={() => setScale((s) => Math.min(5, s + 0.5))}
          className="w-8 h-8 flex items-center justify-center hover:bg-white/10"
          style={{ border: `1px solid ${COLORS.blanco}` }}
        >
          <Plus size={14} />
        </button>
        <button
          onClick={() => {
            setScale(1);
            setPos({ x: 0, y: 0 });
          }}
          className="px-3 h-8 flex items-center justify-center hover:bg-white/10 text-[10px]"
          style={{ border: `1px solid ${COLORS.blanco}` }}
        >
          Reset
        </button>
      </div>

      {/* Navegación */}
      {onPrev && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            onPrev();
          }}
          className="absolute left-6 top-1/2 -translate-y-1/2 p-4 z-10 hover:bg-white/10 transition"
          style={{ color: COLORS.blanco, border: `1px solid ${COLORS.blanco}` }}
        >
          <ChevronLeft size={28} />
        </button>
      )}
      {onNext && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            onNext();
          }}
          className="absolute right-6 top-1/2 -translate-y-1/2 p-4 z-10 hover:bg-white/10 transition"
          style={{ color: COLORS.blanco, border: `1px solid ${COLORS.blanco}` }}
        >
          <ChevronRight size={28} />
        </button>
      )}

      {/* Imagen */}
      <div
        className="relative overflow-hidden w-full h-full flex items-center justify-center"
        onClick={(e) => {
          if (e.target === e.currentTarget) onClose();
        }}
      >
        <img
          src={src}
          alt={alt}
          draggable={false}
          onDoubleClick={toggleZoom}
          onMouseDown={onMouseDown}
          className="select-none"
          style={{
            maxWidth: "90vw",
            maxHeight: "90vh",
            transform: `translate(${pos.x}px, ${pos.y}px) scale(${scale})`,
            transition: dragging ? "none" : "transform 0.2s ease-out",
            cursor: scale > 1 ? (dragging ? "grabbing" : "grab") : "zoom-in",
            userSelect: "none",
          }}
        />
      </div>

      {/* Hint inferior */}
      <div
        className="absolute bottom-6 left-1/2 -translate-x-1/2 text-[10px] uppercase tracking-widest"
        style={{ color: "rgba(255,255,255,0.6)", fontFamily: FONT_STACK_MONO, letterSpacing: "0.2em" }}
      >
        Scroll para zoom · Doble click para acercar · Arrastrá para mover · ESC para salir
      </div>
    </div>
  );
}

function ProductDetailPage({ productId }) {
  const { products, addToCart, nav } = useStore();
  const product = products.find((p) => p.id === productId);
  const [selectedSize, setSelectedSize] = useState(null);
  const [selectedColor, setSelectedColor] = useState(product?.colors[0]);
  const [imgIdx, setImgIdx] = useState(0);
  const [added, setAdded] = useState(false);
  const [zoomOpen, setZoomOpen] = useState(false);
  const [shipping, setShipping] = useState("economy");

  useEffect(() => {
    window.scrollTo(0, 0);
    setSelectedSize(null);
    setSelectedColor(product?.colors[0]);
    setImgIdx(0);
    setZoomOpen(false);
  }, [productId]);

  if (!product) return <div className="pt-32 text-center">Producto no encontrado</div>;

  const brand = BRANDS[product.brand];
  const imagesAvailable = [0, 1, 2].filter((i) => img(product.imageKey, i));

  const onAdd = () => {
    if (!selectedSize) return;
    const shippingExtra = shipping === "express" ? 50 : 0;
    addToCart({ productId: product.id, size: selectedSize, color: selectedColor, qty: 1, shipping, shippingExtra });
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  return (
    <div className="pt-24 pb-20" style={{ background: COLORS.fondoLight, minHeight: "100vh" }}>
      {zoomOpen && (
        <ZoomModal
          src={img(product.imageKey, imgIdx, product)}
          alt={product.name}
          onClose={() => setZoomOpen(false)}
          onPrev={imagesAvailable.length > 1 ? () => setImgIdx((i) => (i - 1 + imagesAvailable.length) % imagesAvailable.length) : null}
          onNext={imagesAvailable.length > 1 ? () => setImgIdx((i) => (i + 1) % imagesAvailable.length) : null}
        />
      )}
      <div className="max-w-[1600px] mx-auto px-6 py-8">
        <button
          onClick={() => window.history.back()}
          className="text-xs uppercase tracking-widest mb-6 inline-flex items-center gap-2 hover:opacity-80"
          style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
        >
          <ArrowLeft size={14} /> Volver
        </button>

        <div className="grid md:grid-cols-2 gap-8 lg:gap-16">
          {/* Galería */}
          <div className="flex flex-col gap-4">
            <div
              className="aspect-square relative overflow-hidden group cursor-zoom-in"
              style={{ background: COLORS.cardLight, border: `1px solid ${COLORS.borderLight}` }}
              onClick={() => setZoomOpen(true)}
            >
              <img
                key={imgIdx}
                src={img(product.imageKey, imgIdx, product)}
                alt={product.name}
                className="w-full h-full object-cover"
              />
              {/* Hint de zoom */}
              <div
                className="absolute bottom-3 right-3 px-2 py-1 text-[10px] uppercase tracking-widest pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity"
                style={{
                  background: "rgba(10,10,10,0.85)",
                  color: COLORS.blanco,
                  fontFamily: FONT_STACK_DISPLAY,
                  letterSpacing: "0.15em",
                }}
              >
                🔍 Click para zoom
              </div>

              {imagesAvailable.length > 1 && (
                <>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      setImgIdx((i) => (i - 1 + imagesAvailable.length) % imagesAvailable.length);
                    }}
                    className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full"
                    style={{ background: "rgba(10,10,10,0.85)", color: COLORS.blanco }}
                  >
                    <ChevronLeft size={20} />
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      setImgIdx((i) => (i + 1) % imagesAvailable.length);
                    }}
                    className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full"
                    style={{ background: "rgba(10,10,10,0.85)", color: COLORS.blanco }}
                  >
                    <ChevronRight size={20} />
                  </button>
                </>
              )}
            </div>
            <div className="grid grid-cols-3 gap-2">
              {imagesAvailable.map((i) => (
                <button
                  key={i}
                  onClick={() => setImgIdx(i)}
                  className="aspect-square relative overflow-hidden"
                  style={{
                    border: `2px solid ${imgIdx === i ? COLORS.celesteDeep : COLORS.borderLight}`,
                  }}
                >
                  <img src={img(product.imageKey, i, product)} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </div>

          {/* Info */}
          <div>
            <div className="flex items-center gap-2 mb-4">
              <Badge color="celeste">{brand.name}</Badge>
              {product.type === "encargo" ? (
                <Badge color="amarillo">ENCARGO · 4-5 SEM</Badge>
              ) : product.stock > 0 ? (
                <Badge color="green">STOCK · {product.stock} disp.</Badge>
              ) : (
                <Badge color="red">SIN STOCK</Badge>
              )}
            </div>
            <h1
              className="text-4xl md:text-6xl font-black leading-[0.9] mb-4"
              style={{ fontFamily: FONT_STACK_DISPLAY, color: COLORS.negro, letterSpacing: "-0.03em" }}
            >
              {product.name}
            </h1>
            <div
              className="text-xs uppercase tracking-widest mb-6"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_MONO, letterSpacing: "0.2em" }}
            >
              MODEL REF: {product.model}
            </div>
            <p
              className="text-base mb-8 max-w-lg"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY, lineHeight: 1.7 }}
            >
              {product.description}
            </p>

            <div className="mb-8">
              <Price usd={product.priceUSD} size="xl" />
            </div>

            {/* Color */}
            {product.colors.length > 0 && (
              <div className="mb-8">
                <div
                  className="text-xs uppercase tracking-widest mb-3"
                  style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
                >
                  Color · <span style={{ color: COLORS.negro }}>{selectedColor}</span>
                </div>
                <div className="flex flex-wrap gap-2">
                  {product.colors.map((c) => (
                    <button
                      key={c}
                      onClick={() => setSelectedColor(c)}
                      className="px-4 py-2 text-xs uppercase font-black tracking-widest"
                      style={{
                        fontFamily: FONT_STACK_DISPLAY,
                        background: selectedColor === c ? COLORS.negro : "transparent",
                        color: selectedColor === c ? COLORS.blanco : COLORS.negro,
                        border: `1px solid ${selectedColor === c ? COLORS.negro : COLORS.borderLight}`,
                        letterSpacing: "0.15em",
                      }}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Talle */}
            <div className="mb-8">
              <div
                className="text-xs uppercase tracking-widest mb-3"
                style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
              >
                Talle {selectedSize ? <span style={{ color: COLORS.negro }}>· {selectedSize}</span> : null}
              </div>
              <div className="flex flex-wrap gap-2">
                {product.sizes.map((s) => (
                  <button
                    key={s}
                    onClick={() => setSelectedSize(s)}
                    className="w-16 h-14 text-sm uppercase font-black transition-colors"
                    style={{
                      fontFamily: FONT_STACK_DISPLAY,
                      background: selectedSize === s ? COLORS.amarillo : "transparent",
                      color: selectedSize === s ? COLORS.negro : COLORS.negro,
                      border: `1px solid ${selectedSize === s ? COLORS.amarillo : COLORS.borderLight}`,
                    }}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>

            {/* Envío */}
            <div className="mb-8">
              <div
                className="text-xs uppercase tracking-widest mb-3"
                style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
              >
                Tipo de envío
              </div>
              <div className="flex flex-col gap-2">
                {[
                  {
                    id: "economy",
                    label: "Economy",
                    sub: "3 a 4 semanas desde origen",
                    extra: 0,
                    badge: "GRATIS",
                    badgeColor: "#10B981",
                  },
                  {
                    id: "express",
                    label: "Express",
                    sub: "1 semana — envío prioritario",
                    extra: 50,
                    badge: "+US$50",
                    badgeColor: COLORS.amarillo,
                  },
                ].map((opt) => (
                  <button
                    key={opt.id}
                    onClick={() => setShipping(opt.id)}
                    className="flex items-center justify-between px-4 py-3 text-left transition-all"
                    style={{
                      border: `2px solid ${shipping === opt.id ? COLORS.celesteDeep : COLORS.borderLight}`,
                      background: shipping === opt.id ? "rgba(74,144,194,0.06)" : COLORS.blanco,
                    }}
                  >
                    <div className="flex items-center gap-3">
                      <div
                        className="w-4 h-4 rounded-full border-2 flex items-center justify-center shrink-0"
                        style={{ borderColor: shipping === opt.id ? COLORS.celesteDeep : COLORS.borderLight }}
                      >
                        {shipping === opt.id && (
                          <div
                            className="w-2 h-2 rounded-full"
                            style={{ background: COLORS.celesteDeep }}
                          />
                        )}
                      </div>
                      <div>
                        <div
                          className="text-sm font-black"
                          style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.05em" }}
                        >
                          {opt.label}
                        </div>
                        <div
                          className="text-xs"
                          style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}
                        >
                          {opt.sub}
                        </div>
                      </div>
                    </div>
                    <span
                      className="text-xs font-black px-2 py-0.5"
                      style={{
                        background: opt.badgeColor,
                        color: opt.id === "express" ? COLORS.negro : COLORS.blanco,
                        fontFamily: FONT_STACK_DISPLAY,
                        letterSpacing: "0.1em",
                      }}
                    >
                      {opt.badge}
                    </span>
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-3">
              <Btn
                variant="primary"
                size="lg"
                onClick={onAdd}
                disabled={!selectedSize || (product.type === "stock" && product.stock === 0)}
                className="flex-1"
              >
                {added ? (
                  <>
                    <Check size={18} /> Agregado
                  </>
                ) : !selectedSize ? (
                  "Elegí un talle"
                ) : (
                  <>
                    <ShoppingBag size={18} /> Agregar al carrito
                  </>
                )}
              </Btn>
            </div>

            {/* Info extra */}
            <div className="mt-12 grid grid-cols-2 gap-3 text-xs">
              {[
                { i: Shield, t: "100% Original", s: "O devolución total" },
                { i: Zap, t: "Envío nacional", s: "48hs AMBA / 5d interior" },
                { i: Globe, t: "Tracking desde origen", s: "USA/China → AR" },
                { i: RefreshCw, t: "Cambio en 7 días", s: "Talle o producto" },
              ].map((f, i) => {
                const Icon = f.i;
                return (
                  <div
                    key={i}
                    className="p-3 flex items-start gap-3"
                    style={{ border: `1px solid ${COLORS.borderLight}`, background: COLORS.cardLight }}
                  >
                    <Icon size={16} style={{ color: COLORS.celesteDeep }} className="mt-0.5" />
                    <div>
                      <div
                        className="text-xs uppercase font-black"
                        style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.1em" }}
                      >
                        {f.t}
                      </div>
                      <div style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}>{f.s}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   CART
   ============================================================ */

function CartPage() {
  const { cart, products, removeFromCart, updateQty, nav, exchangeRate } = useStore();
  const items = cart
    .map((c) => ({ ...c, product: products.find((p) => p.id === c.productId) }))
    .filter((c) => c.product);
  const productsTotalUSD = items.reduce((a, b) => a + b.product.priceUSD * b.qty, 0);
  const shippingTotalUSD = items.reduce((a, b) => a + (b.shippingExtra || 0), 0);
  const totalUSD = productsTotalUSD + shippingTotalUSD;
  const totalARS = Math.round((totalUSD * exchangeRate.value) / 100) * 100;

  return (
    <div className="pt-24" style={{ background: COLORS.fondoLight, minHeight: "100vh" }}>
      <div className="max-w-6xl mx-auto px-6 py-12">
        <div
          className="text-xs uppercase tracking-widest mb-3"
          style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.3em" }}
        >
          Tu carrito
        </div>
        <h1
          className="text-7xl md:text-9xl font-black leading-[0.85] mb-12"
          style={{ fontFamily: FONT_STACK_DISPLAY, color: COLORS.negro, letterSpacing: "-0.05em" }}
        >
          Checkout
        </h1>

        {items.length === 0 ? (
          <div className="py-24 text-center">
            <ShoppingBag size={64} className="mx-auto mb-6 opacity-30" style={{ color: COLORS.negro }} />
            <p
              className="text-2xl mb-6"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "-0.02em" }}
            >
              Tu carrito está vacío
            </p>
            <Btn variant="primary" onClick={() => nav({ name: "stock" })}>
              Ver productos
            </Btn>
          </div>
        ) : (
          <div className="grid lg:grid-cols-[1fr_360px] gap-8">
            <div className="flex flex-col gap-3">
              {items.map((it, idx) => (
                <div
                  key={`${it.productId}-${it.size}-${it.color}`}
                  className="flex gap-4 p-4"
                  style={{ background: COLORS.cardLight, border: `1px solid ${COLORS.borderLight}` }}
                >
                  <img
                    src={img(it.product.imageKey, 0, it.product)}
                    alt={it.product.name}
                    className="w-24 h-24 object-cover"
                  />
                  <div className="flex-1 min-w-0">
                    <div
                      className="text-[10px] uppercase tracking-widest mb-1"
                      style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.15em" }}
                    >
                      {BRANDS[it.product.brand].name}
                    </div>
                    <div
                      className="text-sm font-black mb-1 truncate"
                      style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY }}
                    >
                      {it.product.name}
                    </div>
                    <div className="text-xs mb-3 flex items-center gap-2 flex-wrap" style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}>
                      <span>Talle {it.size} · {it.color}</span>
                      {it.shipping && (
                        <span
                          className="px-1.5 py-0.5 text-[10px] font-black uppercase"
                          style={{
                            background: it.shipping === "express" ? COLORS.amarillo : "#10B981",
                            color: it.shipping === "express" ? COLORS.negro : COLORS.blanco,
                            fontFamily: FONT_STACK_DISPLAY,
                            letterSpacing: "0.1em",
                          }}
                        >
                          {it.shipping === "express" ? "⚡ Express" : "Economy"}
                        </span>
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => updateQty(it.productId, it.size, it.color, it.qty - 1)}
                        className="w-8 h-8 flex items-center justify-center"
                        style={{ border: `1px solid ${COLORS.borderLight}`, color: COLORS.negro, background: COLORS.blanco }}
                      >
                        <Minus size={14} />
                      </button>
                      <span
                        className="w-8 text-center text-sm font-black"
                        style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY }}
                      >
                        {it.qty}
                      </span>
                      <button
                        onClick={() => updateQty(it.productId, it.size, it.color, it.qty + 1)}
                        className="w-8 h-8 flex items-center justify-center"
                        style={{ border: `1px solid ${COLORS.borderLight}`, color: COLORS.negro, background: COLORS.blanco }}
                      >
                        <Plus size={14} />
                      </button>
                    </div>
                  </div>
                  <div className="flex flex-col items-end justify-between">
                    <button
                      onClick={() => removeFromCart(it.productId, it.size, it.color)}
                      style={{ color: COLORS.grisTextLight }}
                    >
                      <Trash2 size={16} />
                    </button>
                    <Price usd={it.product.priceUSD * it.qty} size="sm" />
                  </div>
                </div>
              ))}
            </div>

            <div
              className="p-6 h-fit sticky top-24"
              style={{ background: COLORS.cardLight, border: `1px solid ${COLORS.borderLight}` }}
            >
              <div
                className="text-xs uppercase tracking-widest mb-4"
                style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
              >
                Resumen
              </div>
              <div className="flex justify-between py-2 text-sm" style={{ color: COLORS.grisTextLight }}>
                <span style={{ fontFamily: FONT_STACK_BODY }}>Items</span>
                <span style={{ fontFamily: FONT_STACK_MONO }}>{items.reduce((a, b) => a + b.qty, 0)}</span>
              </div>
              <div className="flex justify-between py-2 text-sm" style={{ color: COLORS.grisTextLight }}>
                <span style={{ fontFamily: FONT_STACK_BODY }}>Productos</span>
                <span style={{ fontFamily: FONT_STACK_MONO }}>US${productsTotalUSD.toLocaleString("en-US")}</span>
              </div>
              <div className="flex justify-between py-2 text-sm" style={{ color: COLORS.grisTextLight }}>
                <span style={{ fontFamily: FONT_STACK_BODY }}>Envío</span>
                <span style={{ fontFamily: FONT_STACK_MONO, color: shippingTotalUSD > 0 ? COLORS.negro : "#10B981" }}>
                  {shippingTotalUSD > 0 ? `US$${shippingTotalUSD}` : "Gratis"}
                </span>
              </div>
              <div
                className="flex justify-between py-4 my-4 border-y text-sm"
                style={{ borderColor: COLORS.borderLight, color: COLORS.grisTextLight }}
              >
                <span style={{ fontFamily: FONT_STACK_BODY }}>Cotización USD</span>
                <span style={{ fontFamily: FONT_STACK_MONO }}>${exchangeRate.value.toLocaleString("es-AR")}</span>
              </div>
              <div className="flex justify-between items-end pb-6">
                <span
                  className="text-xs uppercase font-black"
                  style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
                >
                  Total
                </span>
                <div className="text-right">
                  <div
                    className="text-2xl font-black"
                    style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY }}
                  >
                    US${totalUSD.toLocaleString("en-US")}
                  </div>
                  <div className="text-xs" style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_MONO }}>
                    ≈ ${totalARS.toLocaleString("es-AR")} ARS
                  </div>
                </div>
              </div>
              <Btn variant="primary" size="lg" className="w-full" onClick={() => {
                // Construir mensaje detallado con todo el carrito
                const lines = [];
                lines.push("👋 *Hola PIOLA.AR!* Quiero hacer este pedido:");
                lines.push("");
                items.forEach((it, i) => {
                  lines.push(`*${i + 1}. ${it.product.name}*`);
                  lines.push(`   Marca: ${BRANDS[it.product.brand].name}`);
                  lines.push(`   Talle: ${it.size} · Color: ${it.color}`);
                  lines.push(`   Cantidad: ${it.qty}`);
                  if (it.shipping) {
                    lines.push(`   Envío: ${it.shipping === "express" ? "⚡ Express (1 sem, +US$50)" : "Economy (3-4 sem, gratis)"}`);
                  }
                  lines.push(`   Subtotal: US$${it.product.priceUSD * it.qty}${it.shippingExtra ? ` + US$${it.shippingExtra} envío` : ""}`);
                  lines.push("");
                });
                lines.push("━━━━━━━━━━━━━━━━━━");
                lines.push(`*Productos:* US$${productsTotalUSD}`);
                if (shippingTotalUSD > 0) lines.push(`*Envío:* US$${shippingTotalUSD}`);
                else lines.push(`*Envío:* GRATIS`);
                lines.push(`*TOTAL:* US$${totalUSD} (≈ $${totalARS.toLocaleString("es-AR")} ARS)`);
                lines.push(`_Cotización blue: $${exchangeRate.value.toLocaleString("es-AR")}_`);
                lines.push("");
                lines.push("Quedo atento para coordinar pago y envío 🙌");

                const phone = "5491160130069";
                const text = encodeURIComponent(lines.join("\n"));
                window.open(`https://wa.me/${phone}?text=${text}`, "_blank");
              }}>
                Finalizar por WhatsApp <ArrowRight size={16} />
              </Btn>
              <p
                className="text-[10px] mt-3 text-center"
                style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}
              >
                Coordinamos pago + envío por WhatsApp
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

