/* ============================================================
   ADMIN: Subir producto nuevo — flujo simulado con "IA"
   ============================================================ */

function NewProductFlow({ onDone }) {
  const { products, setProducts, addProduct, updateProduct, deleteProduct } = useStore();
  const [step, setStep] = useState(1); // 1=upload 2=identify 3=form
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [aiSuggestion, setAiSuggestion] = useState(null);
  const [form, setForm] = useState({
    name: "",
    brand: "tnf",
    model: "",
    category: "Camperas",
    type: "stock",
    priceUSD: 0,
    description: "",
    sizes: ["S", "M", "L", "XL"],
    colors: [""],
    stock: 1,
    featured: false,
    imageKey: null,
  });

  const onFiles = (fs) => {
    const arr = Array.from(fs).slice(0, 6);
    setFiles(arr);
    const urls = arr.map((f) => URL.createObjectURL(f));
    setPreviews(urls);
  };

  const runAI = () => {
    // Simulación: en prod esto llamaría a Claude Vision / GPT-4V con las imágenes.
    setStep(2);
    setTimeout(() => {
      // elegimos una sugerencia random de los existing brands
      const brands = Object.keys(BRANDS);
      const sug = {
        brand: brands[Math.floor(Math.random() * brands.length)],
        name: "Producto identificado (editar)",
        model: "REF-XXXX",
        category: "Camperas",
        confidence: 0.84 + Math.random() * 0.14,
      };
      setAiSuggestion(sug);
      setForm((f) => ({ ...f, brand: sug.brand, name: sug.name, model: sug.model, category: sug.category }));
      setStep(3);
    }, 2200);
  };

  const save = async () => {
    const id = `custom_${Date.now()}`;
    const newProd = {
      ...form,
      id,
      imageKey: id,
      colors: form.colors.filter((c) => c.trim()),
      _previewUrls: previews,
      images: previews,
    };
    const ok = await addProduct(newProd);
    if (ok) onDone();
    else alert("Error al guardar el producto. Intentá de nuevo.");
  };

  return (
    <div className="max-w-4xl">
      {/* Steps indicator */}
      <div className="flex items-center gap-2 mb-8">
        {["Subir fotos", "Identificar con IA", "Completar datos"].map((s, i) => (
          <React.Fragment key={i}>
            <div
              className="px-3 py-1 text-xs uppercase tracking-widest"
              style={{
                fontFamily: FONT_STACK_DISPLAY,
                letterSpacing: "0.15em",
                background: step > i ? COLORS.celeste : step === i + 1 ? COLORS.amarillo : "transparent",
                color: step >= i + 1 ? COLORS.negro : COLORS.grisText,
                border: `1px solid ${step >= i + 1 ? (step > i ? COLORS.celeste : COLORS.amarillo) : COLORS.grisBorder}`,
              }}
            >
              {i + 1}. {s}
            </div>
            {i < 2 && <ChevronRight size={14} style={{ color: COLORS.grisTextLight }} />}
          </React.Fragment>
        ))}
      </div>

      {step === 1 && (
        <div>
          <DropZone onFiles={onFiles} />
          {previews.length > 0 && (
            <>
              <div className="mt-6 grid grid-cols-3 md:grid-cols-6 gap-2">
                {previews.map((p, i) => (
                  <div
                    key={i}
                    className="aspect-square relative overflow-hidden"
                    style={{ border: `1px solid ${COLORS.borderLight}` }}
                  >
                    <img src={p} alt="" className="w-full h-full object-cover" />
                    <div
                      className="absolute top-1 right-1 w-5 h-5 flex items-center justify-center text-[10px] font-black"
                      style={{ background: COLORS.amarillo, color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY }}
                    >
                      {i + 1}
                    </div>
                  </div>
                ))}
              </div>
              <div className="mt-6 flex gap-3">
                <Btn variant="primary" size="lg" onClick={runAI}>
                  <Sparkles size={16} /> Identificar con IA
                </Btn>
                <Btn variant="ghost" onClick={() => { setFiles([]); setPreviews([]); }}>
                  Limpiar
                </Btn>
              </div>
            </>
          )}
        </div>
      )}

      {step === 2 && (
        <div className="py-24 text-center">
          <div
            className="inline-block mb-6 piola-spin-fast"
          >
            <Sparkles size={48} style={{ color: COLORS.celeste }} />
          </div>
          <h3
            className="text-3xl font-black mb-2"
            style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "-0.02em" }}
          >
            Analizando imágenes...
          </h3>
          <p style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}>
            Detectando marca, modelo, colores y talles visibles.
          </p>
          <div
            className="mt-6 inline-block px-4 py-2 text-xs"
            style={{
              background: "rgba(116,172,223,0.1)",
              color: COLORS.celesteDeep,
              fontFamily: FONT_STACK_MONO,
              border: `1px solid ${COLORS.celeste}`,
            }}
          >
            demo: simula Claude Vision / GPT-4V — en prod identifica de verdad
          </div>
        </div>
      )}

      {step === 3 && (
        <div>
          {aiSuggestion && (
            <div
              className="mb-6 p-4 flex items-start gap-3"
              style={{
                background: "rgba(16,185,129,0.08)",
                border: "1px solid #10B981",
              }}
            >
              <Check size={18} style={{ color: "#10B981" }} className="mt-0.5 shrink-0" />
              <div className="flex-1 text-sm" style={{ color: COLORS.negro, fontFamily: FONT_STACK_BODY }}>
                <strong>IA detectó:</strong> {BRANDS[aiSuggestion.brand].name} ·{" "}
                <span style={{ color: COLORS.grisTextLight }}>
                  confianza {(aiSuggestion.confidence * 100).toFixed(0)}%
                </span>
                <div className="text-xs mt-1" style={{ color: COLORS.grisTextLight }}>
                  Revisá los datos, ajustá lo que haga falta y guardá.
                </div>
              </div>
            </div>
          )}
          <ProductForm form={form} setForm={setForm} onSave={save} onCancel={onDone} />
        </div>
      )}
    </div>
  );
}

function DropZone({ onFiles }) {
  const [dragging, setDragging] = useState(false);
  const inputRef = useRef();
  return (
    <div
      onDragOver={(e) => {
        e.preventDefault();
        setDragging(true);
      }}
      onDragLeave={() => setDragging(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDragging(false);
        onFiles(e.dataTransfer.files);
      }}
      onClick={() => inputRef.current?.click()}
      className="border-2 border-dashed p-16 text-center cursor-pointer transition-all"
      style={{
        borderColor: dragging ? COLORS.amarillo : COLORS.grisBorder,
        background: dragging ? "rgba(246,180,14,0.05)" : "transparent",
      }}
    >
      <input
        ref={inputRef}
        type="file"
        multiple
        accept="image/*"
        className="hidden"
        onChange={(e) => onFiles(e.target.files)}
      />
      <Upload size={40} className="mx-auto mb-4" style={{ color: COLORS.celeste }} />
      <h3
        className="text-2xl font-black mb-2"
        style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "-0.02em" }}
      >
        Subí las fotos del producto
      </h3>
      <p className="text-sm mb-4" style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}>
        Arrastrá el zip descomprimido, o seleccioná hasta 6 imágenes
      </p>
      <div
        className="inline-block px-3 py-1 text-xs"
        style={{ background: COLORS.grisBorder, color: COLORS.grisTextLight, fontFamily: FONT_STACK_MONO }}
      >
        JPG · PNG · WEBP · máx 10MB c/u
      </div>
    </div>
  );
}

function EditProductForm({ product, onSave, onCancel }) {
  const [form, setForm] = useState({ ...product });
  const [tab, setTab] = useState("datos"); // "datos" | "fotos"

  return (
    <div className="max-w-5xl">
      {/* Tabs */}
      <div className="flex gap-0 mb-8 border-b" style={{ borderColor: COLORS.borderLight }}>
        {[{ id: "datos", label: "Datos del producto" }, { id: "fotos", label: "Fotos" }].map((t) => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className="px-6 py-3 text-xs uppercase font-black tracking-widest border-b-2 transition-all -mb-px"
            style={{
              fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em",
              borderColor: tab === t.id ? COLORS.negro : "transparent",
              color: tab === t.id ? COLORS.negro : COLORS.grisTextLight,
            }}>
            {t.label}
          </button>
        ))}
      </div>

      {tab === "datos" && (
        <ProductForm form={form} setForm={setForm}
          onSave={() => onSave(form)}
          onCancel={onCancel || (() => onSave(product))}
          edit />
      )}
      {tab === "fotos" && (
        <PhotoManager
          product={form}
          onSave={(upd) => { setForm(upd); setTab("datos"); }}
          onCancel={() => setTab("datos")}
          inline
        />
      )}
    </div>
  );
}

/* ============================================================
   PhotoManager — reemplazar las fotos de un producto existente
   ============================================================ */

function PhotoManager({ product, onSave, onCancel }) {
  // Arrancamos con las 3 fotos actuales (si son base64 del zip, las convertimos a dataURI)
  const initial = [0, 1, 2].map((i) => img(product.imageKey, i, product) || null);
  const [photos, setPhotos] = useState(initial);
  const [dragIdx, setDragIdx] = useState(null);
  const inputRefs = [useRef(), useRef(), useRef()];
  const bulkInputRef = useRef();

  const setPhotoAt = (idx, file) => {
    if (!file) return;
    // Leemos el file como dataURL para que persista
    const reader = new FileReader();
    reader.onload = (e) => {
      const dataUrl = e.target.result;
      setPhotos((ps) => {
        const next = [...ps];
        next[idx] = dataUrl;
        return next;
      });
    };
    reader.readAsDataURL(file);
  };

  const onBulk = (files) => {
    const arr = Array.from(files).slice(0, 3);
    arr.forEach((f, i) => setPhotoAt(i, f));
  };

  const removePhoto = (idx) => {
    setPhotos((ps) => {
      const next = [...ps];
      next[idx] = null;
      return next;
    });
  };

  const save = () => {
    // Guardamos las fotos nuevas como _previewUrls (array de dataURIs)
    const newPhotos = photos.filter((p) => p);
    const updated = {
      ...product,
      _previewUrls: newPhotos,
      // Mantenemos la imageKey original para fallback, pero las _previewUrls tienen prioridad en img()
    };
    onSave(updated);
  };

  const hasChanges = photos.some((p, i) => p !== initial[i]);
  const hasPhotos = photos.some((p) => p);

  const labels = ["Principal (catálogo)", "Lifestyle / hover", "Detalle / bordado"];

  return (
    <div className="max-w-5xl">
      <div
        className="mb-8 p-4 text-sm flex items-start gap-3"
        style={{
          background: "rgba(116,172,223,0.1)",
          border: `1px solid ${COLORS.celeste}`,
          color: COLORS.negro,
          fontFamily: FONT_STACK_BODY,
        }}
      >
        <ImageIcon size={18} style={{ color: COLORS.celesteDeep }} className="mt-0.5 shrink-0" />
        <div>
          <strong>Consejo:</strong> Para que las fotos se vean bien en el catálogo, conviene que las tres sean del <strong>mismo ángulo</strong> y con <strong>fondo blanco</strong> uniforme. Te recomiendo pasarlas antes por{" "}
          <a
            href="https://remove.bg"
            target="_blank"
            rel="noopener"
            style={{ color: COLORS.celesteDeep, textDecoration: "underline" }}
          >
            remove.bg
          </a>{" "}
          o{" "}
          <a
            href="https://photoroom.com"
            target="_blank"
            rel="noopener"
            style={{ color: COLORS.celesteDeep, textDecoration: "underline" }}
          >
            photoroom.com
          </a>{" "}
          para sacarles el fondo.
        </div>
      </div>

      <div className="mb-6 flex items-center justify-between flex-wrap gap-4">
        <div>
          <div
            className="text-xs uppercase tracking-widest mb-1"
            style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
          >
            Producto
          </div>
          <div
            className="text-2xl font-black"
            style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "-0.02em" }}
          >
            {product.name}
          </div>
        </div>
        <input
          ref={bulkInputRef}
          type="file"
          accept="image/*"
          multiple
          className="hidden"
          onChange={(e) => onBulk(e.target.files)}
        />
        <Btn variant="celeste" onClick={() => bulkInputRef.current?.click()}>
          <Upload size={14} /> Subir 3 fotos de una
        </Btn>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        {[0, 1, 2].map((i) => (
          <div key={i} className="flex flex-col gap-2">
            <div
              className="text-[10px] uppercase tracking-widest flex items-center justify-between"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
            >
              <span>
                {String(i + 1).padStart(2, "0")} · {labels[i]}
              </span>
              {photos[i] && (
                <button
                  onClick={() => removePhoto(i)}
                  className="hover:text-red-500"
                  style={{ color: COLORS.grisTextLight }}
                  title="Quitar"
                >
                  <X size={14} />
                </button>
              )}
            </div>
            <input
              ref={inputRefs[i]}
              type="file"
              accept="image/*"
              className="hidden"
              onChange={(e) => setPhotoAt(i, e.target.files[0])}
            />
            <div
              onClick={() => inputRefs[i].current?.click()}
              onDragOver={(e) => {
                e.preventDefault();
                setDragIdx(i);
              }}
              onDragLeave={() => setDragIdx(null)}
              onDrop={(e) => {
                e.preventDefault();
                setDragIdx(null);
                if (e.dataTransfer.files[0]) setPhotoAt(i, e.dataTransfer.files[0]);
              }}
              className="aspect-square cursor-pointer flex items-center justify-center relative overflow-hidden transition-all"
              style={{
                background: photos[i] ? COLORS.blanco : COLORS.cardLight,
                border: `2px dashed ${dragIdx === i ? COLORS.celeste : COLORS.borderLight}`,
              }}
            >
              {photos[i] ? (
                <>
                  <img src={photos[i]} alt="" className="w-full h-full object-cover" />
                  <div
                    className="absolute bottom-0 left-0 right-0 py-1.5 text-[10px] uppercase tracking-widest text-center opacity-0 hover:opacity-100 transition"
                    style={{
                      background: "rgba(10,10,10,0.85)",
                      color: COLORS.blanco,
                      fontFamily: FONT_STACK_DISPLAY,
                      letterSpacing: "0.15em",
                    }}
                  >
                    Click para reemplazar
                  </div>
                </>
              ) : (
                <div className="text-center p-4">
                  <Upload size={28} style={{ color: COLORS.celesteDeep }} className="mx-auto mb-2" />
                  <div
                    className="text-xs uppercase font-black"
                    style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.15em" }}
                  >
                    Subir foto
                  </div>
                  <div
                    className="text-[10px] mt-1"
                    style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_BODY }}
                  >
                    Click o arrastrá acá
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Preview de cómo va a quedar en el catálogo */}
      {hasPhotos && (
        <div className="mb-8">
          <div
            className="text-xs uppercase tracking-widest mb-3"
            style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
          >
            Preview — así se ve en el catálogo
          </div>
          <div className="max-w-xs">
            <div
              className="piola-card-box overflow-hidden"
              style={{ background: COLORS.cardLight, border: `1px solid ${COLORS.borderLight}` }}
            >
              <div className="piola-card-inner">
                <div className="absolute top-3 left-3 z-10 flex flex-col gap-2 items-start">
                  {product.type === "encargo" && <Badge color="amarillo">ENCARGO</Badge>}
                  {product.type === "stock" && product.stock > 0 && <Badge color="celeste">EN STOCK</Badge>}
                </div>
                <div className="absolute inset-0 flex items-center justify-center overflow-hidden">
                  <img src={photos[0] || photos[1] || photos[2]} alt="" className="w-full h-full object-cover" />
                </div>
                <div
                  className="absolute bottom-0 left-0 right-0 p-4 pointer-events-none"
                  style={{ background: "linear-gradient(to top, rgba(255,255,255,0.98), rgba(255,255,255,0.85) 50%, transparent)" }}
                >
                  <div
                    className="text-[10px] uppercase tracking-widest mb-1"
                    style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.15em" }}
                  >
                    {BRANDS[product.brand].name}
                  </div>
                  <div
                    className="text-sm font-black leading-tight truncate"
                    style={{ color: COLORS.negro, fontFamily: FONT_STACK_DISPLAY }}
                  >
                    {product.name}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="flex gap-3">
        <Btn variant="primary" size="lg" onClick={save} disabled={!hasChanges}>
          <Save size={16} /> Guardar fotos
        </Btn>
        <Btn variant="ghost" onClick={onCancel}>
          Cancelar
        </Btn>
      </div>
    </div>
  );
}

function ProductForm({ form, setForm, onSave, onCancel, edit }) {
  const upd = (k, v) => setForm((f) => ({ ...f, [k]: v }));
  return (
    <div className="grid md:grid-cols-2 gap-8">
      <div className="flex flex-col gap-4">
        <Field label="Nombre del producto">
          <input
            className="w-full bg-transparent border p-3 text-sm outline-none focus:border-yellow-500"
            style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY }}
            value={form.name}
            onChange={(e) => upd("name", e.target.value)}
            placeholder="Ej: Nuptse 1996 Retro"
          />
        </Field>

        <div className="grid grid-cols-2 gap-3">
          <Field label="Marca">
            <select
              value={form.brand}
              onChange={(e) => upd("brand", e.target.value)}
              className="w-full bg-transparent border p-3 text-sm outline-none"
              style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY }}
            >
              {Object.values(BRANDS).map((b) => (
                <option key={b.id} value={b.id} style={{ background: COLORS.fondoLight }}>
                  {b.name}
                </option>
              ))}
            </select>
          </Field>
          <Field label="Categoría">
            <select
              value={form.category}
              onChange={(e) => upd("category", e.target.value)}
              className="w-full bg-transparent border p-3 text-sm outline-none"
              style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY }}
            >
              {CATEGORIES.filter((c) => c !== "Todos").map((c) => (
                <option key={c} value={c} style={{ background: COLORS.fondoLight }}>
                  {c}
                </option>
              ))}
            </select>
          </Field>
        </div>

        <Field label="Modelo / referencia">
          <input
            className="w-full bg-transparent border p-3 text-sm outline-none"
            style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_MONO }}
            value={form.model}
            onChange={(e) => upd("model", e.target.value)}
            placeholder="NF0A3C8D"
          />
        </Field>

        <Field label="Descripción">
          <textarea
            rows={4}
            className="w-full bg-transparent border p-3 text-sm outline-none resize-none"
            style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY }}
            value={form.description}
            onChange={(e) => upd("description", e.target.value)}
          />
        </Field>
      </div>

      <div className="flex flex-col gap-4">
        <div className="grid grid-cols-2 gap-3">
          <Field label="Tipo">
            <div className="flex gap-2">
              {["stock", "encargo"].map((t) => (
                <button
                  key={t}
                  onClick={() => upd("type", t)}
                  className="flex-1 py-3 text-xs uppercase font-black tracking-widest"
                  style={{
                    fontFamily: FONT_STACK_DISPLAY,
                    background: form.type === t ? COLORS.amarillo : "transparent",
                    color: form.type === t ? COLORS.negro : COLORS.grisText,
                    border: `1px solid ${form.type === t ? COLORS.amarillo : COLORS.grisBorder}`,
                    letterSpacing: "0.15em",
                  }}
                >
                  {t}
                </button>
              ))}
            </div>
          </Field>
          <Field label="Precio USD">
            <input
              type="number"
              className="w-full bg-transparent border p-3 text-sm outline-none"
              style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_MONO }}
              value={form.priceUSD}
              onChange={(e) => upd("priceUSD", parseInt(e.target.value || 0))}
            />
          </Field>
        </div>

        <Field label="Stock disponible">
          <input
            type="number"
            className="w-full bg-transparent border p-3 text-sm outline-none"
            style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_MONO }}
            value={form.stock}
            onChange={(e) => upd("stock", parseInt(e.target.value || 0))}
          />
        </Field>

        <Field label="Talles disponibles">
          <div className="flex flex-wrap gap-2">
            {SIZES_CLOTHING.concat(["One Size"]).map((s) => (
              <button
                key={s}
                onClick={() => {
                  if (form.sizes.includes(s)) upd("sizes", form.sizes.filter((x) => x !== s));
                  else upd("sizes", [...form.sizes, s]);
                }}
                className="px-3 py-1.5 text-xs uppercase font-black tracking-widest"
                style={{
                  fontFamily: FONT_STACK_DISPLAY,
                  background: form.sizes.includes(s) ? COLORS.celeste : "transparent",
                  color: form.sizes.includes(s) ? COLORS.negro : COLORS.grisText,
                  border: `1px solid ${form.sizes.includes(s) ? COLORS.celeste : COLORS.grisBorder}`,
                  letterSpacing: "0.1em",
                }}
              >
                {s}
              </button>
            ))}
          </div>
        </Field>

        <Field label="Colores disponibles">
          <div className="flex flex-col gap-2">
            {form.colors.map((c, i) => (
              <div key={i} className="flex gap-2">
                <input
                  value={c}
                  onChange={(e) => {
                    const nc = [...form.colors];
                    nc[i] = e.target.value;
                    upd("colors", nc);
                  }}
                  className="flex-1 bg-transparent border p-2 text-sm outline-none"
                  style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY }}
                  placeholder="Ej: TNF Black"
                />
                {form.colors.length > 1 && (
                  <button
                    onClick={() => upd("colors", form.colors.filter((_, j) => j !== i))}
                    className="p-2"
                    style={{ color: COLORS.grisTextLight }}
                  >
                    <X size={14} />
                  </button>
                )}
              </div>
            ))}
            <button
              onClick={() => upd("colors", [...form.colors, ""])}
              className="text-xs uppercase tracking-widest py-2 text-left"
              style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
            >
              + Agregar color
            </button>
          </div>
        </Field>

        <Field label="Opciones">
          <label
            className="flex items-center gap-3 cursor-pointer p-3"
            style={{ border: `1px solid ${COLORS.borderLight}` }}
          >
            <input
              type="checkbox"
              checked={form.featured}
              onChange={(e) => upd("featured", e.target.checked)}
              className="accent-yellow-500"
            />
            <span className="text-sm" style={{ color: COLORS.negro, fontFamily: FONT_STACK_BODY }}>
              Destacar en home page
            </span>
          </label>
        </Field>

        <div className="flex gap-3 mt-4">
          <Btn variant="primary" size="lg" onClick={onSave} className="flex-1">
            <Save size={16} /> {edit ? "Guardar cambios" : "Publicar producto"}
          </Btn>
          <Btn variant="ghost" onClick={onCancel}>Cancelar</Btn>
        </div>
      </div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div>
      <label
        className="text-[10px] uppercase tracking-widest block mb-2"
        style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
      >
        {label}
      </label>
      {children}
    </div>
  );
}

