/* ============================================================
   LOGIN MODAL
   ============================================================ */

function LoginModal() {
  const { handleLogin, setShowLogin } = useStore();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const onSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    const err = await handleLogin(email, password);
    setLoading(false);
    if (err) setError(err);
  };

  return (
    <div
      className="fixed inset-0 z-[200] flex items-center justify-center"
      style={{ background: "rgba(10,10,10,0.6)", backdropFilter: "blur(8px)" }}
      onClick={() => setShowLogin(false)}
    >
      <div
        className="w-full max-w-sm mx-4 p-8"
        style={{ background: COLORS.blanco, border: `1px solid ${COLORS.borderLight}` }}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between mb-6">
          <div>
            <div
              className="text-xs uppercase tracking-widest mb-1"
              style={{ color: COLORS.celesteDeep, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
            >
              Admin
            </div>
            <div
              className="text-2xl font-black"
              style={{ fontFamily: FONT_STACK_DISPLAY, color: COLORS.negro, letterSpacing: "-0.02em" }}
            >
              Iniciar sesión
            </div>
          </div>
          <button onClick={() => setShowLogin(false)} style={{ color: COLORS.grisTextLight }}>
            <X size={22} />
          </button>
        </div>

        <form onSubmit={onSubmit} className="flex flex-col gap-4">
          <div>
            <label
              className="text-[10px] uppercase tracking-widest block mb-2"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
            >
              Email
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="tu@email.com"
              required
              className="w-full border p-3 text-sm outline-none focus:border-blue-400"
              style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY, background: COLORS.blanco }}
            />
          </div>
          <div>
            <label
              className="text-[10px] uppercase tracking-widest block mb-2"
              style={{ color: COLORS.grisTextLight, fontFamily: FONT_STACK_DISPLAY, letterSpacing: "0.2em" }}
            >
              Contraseña
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              required
              className="w-full border p-3 text-sm outline-none focus:border-blue-400"
              style={{ color: COLORS.negro, borderColor: COLORS.borderLight, fontFamily: FONT_STACK_BODY, background: COLORS.blanco }}
            />
          </div>

          {error && (
            <div
              className="text-xs p-3"
              style={{ background: "rgba(239,68,68,0.08)", color: "#EF4444", border: "1px solid #EF4444", fontFamily: FONT_STACK_BODY }}
            >
              {error === "Invalid login credentials" ? "Email o contraseña incorrectos." : error}
            </div>
          )}

          <Btn type="submit" variant="primary" size="lg" disabled={loading} className="w-full mt-2">
            {loading ? "Entrando..." : "Entrar"}
          </Btn>
        </form>
      </div>
    </div>
  );
}

export default function App() {
  const [route, setRoute] = useState({ name: "home" });
  const [cart, setCart] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const exchangeRate = useExchangeRate();
  const { products, setProducts, addProduct, updateProduct, deleteProduct, loaded } = useProducts();

  // Verificar sesión de Supabase al montar
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsAdmin(!!session);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsAdmin(!!session);
    });
    return () => subscription.unsubscribe();
  }, []);

  const nav = (r) => {
    setRoute(r);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const addToCart = (item) => {
    setCart((c) => {
      const existing = c.find(
        (x) => x.productId === item.productId && x.size === item.size && x.color === item.color
      );
      if (existing) {
        return c.map((x) => (x === existing ? { ...x, qty: x.qty + item.qty } : x));
      }
      return [...c, item];
    });
  };

  const removeFromCart = (productId, size, color) => {
    setCart((c) => c.filter((x) => !(x.productId === productId && x.size === size && x.color === color)));
  };

  const updateQty = (productId, size, color, qty) => {
    if (qty <= 0) return removeFromCart(productId, size, color);
    setCart((c) =>
      c.map((x) =>
        x.productId === productId && x.size === size && x.color === color ? { ...x, qty } : x
      )
    );
  };

  const toggleAdmin = async () => {
    if (isAdmin) {
      await supabase.auth.signOut();
      setIsAdmin(false);
      nav({ name: "home" });
    } else {
      setShowLogin(true);
    }
  };

  const handleLogin = async (email, password) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) return error.message;
    setShowLogin(false);
    nav({ name: "admin" });
    return null;
  };

  const ctx = {
    route,
    nav,
    products,
    setProducts,
    addProduct,
    updateProduct,
    deleteProduct,
    cart,
    addToCart,
    removeFromCart,
    updateQty,
    isAdmin,
    toggleAdmin,
    showLogin,
    setShowLogin,
    handleLogin,
    exchangeRate,
  };

  return (
    <StoreCtx.Provider value={ctx}>
      {/* Importar tipografías Google */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Archivo+Black&family=Hanken+Grotesk:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500;700&display=swap');
        body { background: ${COLORS.fondoLight}; color: ${COLORS.negro}; font-family: ${FONT_STACK_BODY}; }
        html { scroll-behavior: smooth; }
        ::selection { background: ${COLORS.amarillo}; color: ${COLORS.negro}; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: ${COLORS.fondoLight}; }
        ::-webkit-scrollbar-thumb { background: ${COLORS.borderLight}; }
        ::-webkit-scrollbar-thumb:hover { background: ${COLORS.amarillo}; }

        /* Animaciones en CSS puro */
        @keyframes piolaFadeIn {
          from { opacity: 0; transform: translateY(16px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes piolaSlideIn {
          from { opacity: 0; transform: translateX(-32px); }
          to { opacity: 1; transform: translateX(0); }
        }
        @keyframes piolaRouteEnter {
          from { opacity: 0; transform: translateY(8px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes piolaSpin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes piolaMarquee {
          from { transform: translateX(0); }
          to { transform: translateX(-50%); }
        }
        @keyframes piolaPulse {
          0%, 100% { opacity: 0.9; }
          50% { opacity: 0.4; }
        }
        /* IMPORTANTE: animations NO usan opacity:0 inicial para evitar que queden invisibles si la anim no corre */
        .piola-fade-in { animation: piolaFadeIn 0.5s ease-out both; }
        .piola-slide-in { animation: piolaSlideIn 0.5s ease-out both; }
        .piola-route-enter { animation: piolaRouteEnter 0.3s ease-out both; }
        .piola-spin { animation: piolaSpin 20s linear infinite; transform-origin: center; }
        .piola-spin-fast { animation: piolaSpin 2s linear infinite; transform-origin: center; }
        .piola-marquee { animation: piolaMarquee 30s linear infinite; }

        /* Aspect ratio 4/5 con fallback por si Tailwind aspect-[4/5] no compila */
        .piola-card-box {
          position: relative;
          width: 100%;
        }
        .piola-card-box::before {
          content: "";
          display: block;
          padding-bottom: 125%; /* 5/4 = 125% */
        }
        .piola-card-inner {
          position: absolute;
          inset: 0;
        }

        /* Botones: hover scale sin framer */
        .piola-btn { transition: transform 0.15s ease, background 0.2s ease; }
        .piola-btn:hover { transform: scale(1.02); }
        .piola-btn:active { transform: scale(0.97); }

        /* Card hover: imagen escala suave */
        .piola-card-img { transition: transform 0.5s ease; }
        .group:hover .piola-card-img { transform: scale(1.08); }
      `}</style>

      <div style={{ background: COLORS.fondoLight, minHeight: "100vh", fontFamily: FONT_STACK_BODY }}>
        <Navbar />
        {showLogin && <LoginModal />}

          <div key={route.name + (route.id || "")} className="piola-route-enter">
            {route.name === "home" && <HomePage />}
            {route.name === "stock" && <CatalogPage type="stock" />}
            {route.name === "encargos" && <CatalogPage type="encargo" />}
            {route.name === "brands" && <BrandsIndexPage />}
            {route.name === "brand" && <BrandPage brandId={route.id} />}
            {route.name === "product" && <ProductDetailPage productId={route.id} />}
            {route.name === "cart" && <CartPage />}
            {route.name === "admin" && <AdminPage />}
          </div>

        <Footer />
      </div>
    </StoreCtx.Provider>
  );
}
